import anthropic
import json
from concurrent.futures import ThreadPoolExecutor

client = anthropic.Anthropic()

def get_weather(city: str) -> str:
    return json.dumps({"city": city, "temp": 20, "desc": "Cloudy"})

def get_time(city: str) -> str:
    return json.dumps({"city": city, "time": "14:30 CET"})

DISPATCH = {"get_weather": get_weather, "get_time": get_time}

TOOLS = [
    {
        "name": "get_weather",
        "description": "Get current weather for a city.",
        "input_schema": {
            "type": "object",
            "properties": {"city": {"type": "string"}},
            "required": ["city"],
        },
    },
    {
        "name": "get_time",
        "description": "Get the current local time in a city.",
        "input_schema": {
            "type": "object",
            "properties": {"city": {"type": "string"}},
            "required": ["city"],
        },
    },
]

messages = [{"role": "user", "content": "What is the weather and time in London?"}]

resp = client.messages.create(
    model="claude-haiku-4-5-20251001",
    max_tokens=512,
    tools=TOOLS,
    messages=messages,
)
messages.append({"role": "assistant", "content": resp.content})

tool_calls = [b for b in resp.content if b.type == "tool_use"]

# Execute tool calls in parallel
def dispatch(block):
    fn = DISPATCH[block.name]
    return {"type": "tool_result", "tool_use_id": block.id, "content": fn(**block.input)}

with ThreadPoolExecutor() as ex:
    results = list(ex.map(dispatch, tool_calls))

messages.append({"role": "user", "content": results})

resp2 = client.messages.create(
    model="claude-haiku-4-5-20251001",
    max_tokens=512,
    tools=TOOLS,
    messages=messages,
)
print(resp2.content[0].text)

import anthropic
import json
import time

client = anthropic.Anthropic()

def call_tool_with_retry(name: str, arguments: dict, max_retries: int = 3) -> str:
    """
    Dispatch a tool call with retry logic for transient errors.
    Returns a JSON string the model can read.
    """
    delay = 1.0
    for attempt in range(max_retries):
        try:
            result = _dispatch(name, arguments)
            return json.dumps({"ok": True, "result": result})
        except TimeoutError:
            if attempt == max_retries - 1:
                return json.dumps({"ok": False, "error": "timeout", "retries": max_retries})
            time.sleep(delay)
            delay *= 2
        except ValueError as exc:
            # Permanent error — do not retry
            return json.dumps({"ok": False, "error": str(exc)})
    return json.dumps({"ok": False, "error": "unknown"})

