import json

def send_email(to: str, subject: str, body: str, dry_run: bool = False) -> str:
    """
    Send an email. When dry_run=True, validate and describe the action without sending.
    """
    # Validate regardless of dry_run
    if "@" not in to:
        return json.dumps({"ok": False, "error": f"Invalid address: {to}"})
    if not subject.strip():
        return json.dumps({"ok": False, "error": "Subject cannot be empty"})

    if dry_run:
        return json.dumps({
            "ok": True,
            "dry_run": True,
            "would_send": {"to": to, "subject": subject, "body_length": len(body)},
        })

    # Real send logic here
